import{j as r,D as n,b as o,c as p,a2 as a,g as s,h as e,f as l,G as c,a3 as i}from"./chunks/framework.BDRKwY9B.js";const P=JSON.parse('{"title":"关于跨平台","description":"本文简单阐述框架跨平台开发的能力","frontmatter":{"title":"关于跨平台","description":"本文简单阐述框架跨平台开发的能力","order":1},"headers":[],"relativePath":"qa/cross-platform.md","filePath":"qa/cross-platform.md","lastUpdated":1778837174000}'),h={name:"qa/cross-platform.md"};function A(b,t,u,B,m,g){const d=n("Mermaid");return o(),p("div",null,[t[1]||(t[1]=a(`<h1 id="关于跨平台" tabindex="-1">关于跨平台 <a class="header-anchor" href="#关于跨平台" aria-label="Permalink to &quot;关于跨平台&quot;">​</a></h1><h2 id="aurorabot-支持哪些平台" tabindex="-1">AuroraBot 支持哪些平台? <a class="header-anchor" href="#aurorabot-支持哪些平台" aria-label="Permalink to &quot;AuroraBot 支持哪些平台?&quot;">​</a></h2><p>当前版本<strong>仅支持 QQ 接入</strong>, 通过 NapCat + <code>nonebot-adapter-onebot</code> 与 QQ 通信。</p><p>但 AuroraBot 的架构从设计之初就是平台无关的 -- <code>apps</code> 层是可插拔的感知器与执行器, 每个 App 通过统一的 <code>PlatformAPI</code> 与宿主交互。换平台只需换 App, 不需要动内核和认知。</p><hr><h2 id="napcat-的跨平台能力如何" tabindex="-1">NapCat 的跨平台能力如何? <a class="header-anchor" href="#napcat-的跨平台能力如何" aria-label="Permalink to &quot;NapCat 的跨平台能力如何?&quot;">​</a></h2><p><a href="https://github.com/NapNeko/NapCatQQ" target="_blank" rel="noreferrer">NapCatQQ</a> 是一个基于 NTQQ 的现代化 Bot 协议端实现, 它对运行环境的支持非常全面:</p><table tabindex="0"><thead><tr><th>部署方式</th><th>适用场景</th><th>说明</th></tr></thead><tbody><tr><td>Windows 原生</td><td>桌面 / 笔记本</td><td>直接运行 exe, 支持 LiteLoader 插件方式</td></tr><tr><td>Linux AppImage</td><td>物理机 / VPS</td><td>单文件运行, 无需安装依赖</td></tr><tr><td>Linux 原生</td><td>物理机 / VPS</td><td>放入 QQ 安装目录运行</td></tr><tr><td>Docker</td><td>服务器 (推荐)</td><td>支持无头模式, 内存占用极低, 可在纯服务器环境无需桌面运行</td></tr><tr><td>macOS</td><td>Mac 用户</td><td>原生支持</td></tr><tr><td>Android Termux</td><td>移动端</td><td>在安卓终端中运行</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">无头模式</p><p>NapCat 的<strong>无头模式</strong> (<code>headless</code>) 是其杀手级特性: 不需要启动 QQ 图形界面即可在服务器上运行, 资源占用极低, 非常适合 Linux 服务器部署。</p></div><p><strong>协议层面</strong>, NapCat 实现了 OneBot v11 标准协议, 这意味着任何支持 OneBot v11 的框架都可以对接它 -- 包括 NoneBot2。</p><hr><h2 id="nonebot2-的跨平台能力如何" tabindex="-1">NoneBot2 的跨平台能力如何? <a class="header-anchor" href="#nonebot2-的跨平台能力如何" aria-label="Permalink to &quot;NoneBot2 的跨平台能力如何?&quot;">​</a></h2><p>NoneBot2 的核心设计思想是 <strong>适配器模式</strong>: 框架核心完全平台无关, 通过各种适配器连接不同平台。</p><h3 id="官方-社区适配器覆盖" tabindex="-1">官方 / 社区适配器覆盖 <a class="header-anchor" href="#官方-社区适配器覆盖" aria-label="Permalink to &quot;官方 / 社区适配器覆盖&quot;">​</a></h3><table tabindex="0"><thead><tr><th>适配器</th><th>对应平台</th><th>成熟度</th></tr></thead><tbody><tr><td><code>nonebot-adapter-onebot</code> v11</td><td>QQ (NapCat / go-cqhttp / Shamrock 等)</td><td>非常成熟</td></tr><tr><td><code>nonebot-adapter-onebot</code> v12</td><td>多平台统一标准</td><td>稳定</td></tr><tr><td><code>nonebot-adapter-telegram</code></td><td>Telegram</td><td>成熟</td></tr><tr><td><code>nonebot-adapter-discord</code></td><td>Discord</td><td>成熟</td></tr><tr><td><code>nonebot-adapter-qq</code></td><td>QQ 官方 Bot API</td><td>稳定</td></tr><tr><td><code>nonebot-adapter-qqguild</code></td><td>QQ 频道</td><td>稳定</td></tr><tr><td><code>nonebot-adapter-feishu</code></td><td>飞书</td><td>稳定</td></tr><tr><td><code>nonebot-adapter-dingtalk</code></td><td>钉钉</td><td>稳定</td></tr><tr><td><code>nonebot-adapter-kaiheila</code></td><td>KOOK (开黑啦)</td><td>稳定</td></tr><tr><td><code>nonebot-adapter-red</code></td><td>Red 协议</td><td>社区维护</td></tr></tbody></table><p>目前 NoneBot2 生态已有 <strong>20+ 平台适配器</strong> 和 <strong>500+ 社区插件</strong>, 跨平台生态非常成熟。</p><h3 id="驱动层" tabindex="-1">驱动层 <a class="header-anchor" href="#驱动层" aria-label="Permalink to &quot;驱动层&quot;">​</a></h3><p>NoneBot2 还提供了多种通信驱动: <code>FastAPI</code>、<code>HTTPX</code>、<code>WebSocket</code> 等, 可以根据部署环境灵活选择。AuroraBot 当前使用的 <code>~fastapi</code> 驱动即可在任何能跑 Python 的环境运行。</p><hr><h2 id="onebot-协议是什么" tabindex="-1">OneBot 协议是什么? <a class="header-anchor" href="#onebot-协议是什么" aria-label="Permalink to &quot;OneBot 协议是什么?&quot;">​</a></h2><p>OneBot 是一套<strong>统一的聊天机器人接口标准</strong>, 它的核心思想是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的框架  &lt;--&gt;  OneBot 协议  &lt;--&gt;  协议端实现 (NapCat 等)  &lt;--&gt;  QQ</span></span></code></pre></div><p>同一个协议可以被多种协议端实现, 例如 OneBot v11 的实现就有 NapCat、go-cqhttp、Shamrock、LLOneBot 等。这意味着即使 NapCat 挂了, 只要换个协议端就能继续工作, 不会被单一实现绑架。</p><hr><h2 id="aurorabot-当前的跨平台现状" tabindex="-1">AuroraBot 当前的跨平台现状 <a class="header-anchor" href="#aurorabot-当前的跨平台现状" aria-label="Permalink to &quot;AuroraBot 当前的跨平台现状&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层面</th><th>当前状态</th></tr></thead><tbody><tr><td>应用层 (<code>apps</code>)</td><td>仅实现 <code>apps/qq</code> 一个 IM 接入 App</td></tr><tr><td>适配器</td><td>仅加载 <code>nonebot-adapter-onebot</code> (OneBot v11)</td></tr><tr><td>协议端</td><td>推荐 NapCat, 也可使用其他 OneBot v11 实现</td></tr><tr><td>部署环境</td><td>Python 3.10+ 能跑的地方就能跑</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">⚠️ 注意</p><p>当前 AuroraBot 仅通过 <code>nonebot-adapter-onebot</code> 连接 QQ。虽然 NoneBot2 本身支持 20+ 平台, 但 AuroraBot 还没有为其他平台编写对应的 App, 也没有加载其他适配器。</p></div><hr><h2 id="未来跨平台支持的图景" tabindex="-1">未来跨平台支持的图景 <a class="header-anchor" href="#未来跨平台支持的图景" aria-label="Permalink to &quot;未来跨平台支持的图景&quot;">​</a></h2><h3 id="短期-扩展-im-平台接入" tabindex="-1">短期: 扩展 IM 平台接入 <a class="header-anchor" href="#短期-扩展-im-平台接入" aria-label="Permalink to &quot;短期: 扩展 IM 平台接入&quot;">​</a></h3><p>AuroraBot 的 App 体系天然支持水平扩展, 未来可以:</p><ol><li><p><strong>编写新的 IM App</strong>: 参照 <code>apps/qq</code> 的模式, 编写 <code>apps/telegram</code>、<code>apps/discord</code> 等 App。每个 App 只需关注接收本平台消息 + 将平台消息转为 <code>AppEvent</code>, 其他的全部交给 <code>platform</code> → <code>kernel</code> → <code>brain</code> 链路处理。</p></li><li><p><strong>加载更多适配器</strong>: 在 <code>pyproject.toml</code> 中声明额外适配器依赖, NoneBot2 启动时自动加载。例如同时启用 OneBot 和 Telegram 适配器, 就会同时收到两个平台的消息。</p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># pyproject.toml 示意 (未来)</span></span>
<span class="line"><span>[tool.nonebot.adapters]</span></span>
<span class="line"><span>nonebot-adapter-onebot = [...]</span></span>
<span class="line"><span>nonebot-adapter-telegram = [...]</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">💡 小贴士</p><p>对 AuroraBot 而言, 跨平台接入的关键不是框架能力 (框架已有), 而是<strong>为每个平台编写对应的 App</strong>。</p></div><h3 id="中期-mcp-适配容器" tabindex="-1">中期: MCP 适配容器 <a class="header-anchor" href="#中期-mcp-适配容器" aria-label="Permalink to &quot;中期: MCP 适配容器&quot;">​</a></h3><p>AuroraBot 正在设计 <strong>MCP (Model Context Protocol) 适配容器</strong>, 让任意 MCP 服务器以 App 形态接入:</p><ul><li>任何遵循 MCP 协议的工具都可以成为 AuroraBot 的能力延伸</li><li>MCP 工具会被自动映射为内核可调用的命令</li><li>内核无需感知 MCP 协议细节, 由适配容器统一处理</li></ul><p>这意味着 <strong>跨平台的概念将从&quot;跨聊天平台&quot;扩展到&quot;跨工具生态&quot;</strong> -- 你的 AuroraBot 不仅能同时在 QQ、Telegram、Discord 上聊天, 还能调用任何 MCP 兼容的外部工具。</p><h3 id="长期-统一多平台体验" tabindex="-1">长期: 统一多平台体验 <a class="header-anchor" href="#长期-统一多平台体验" aria-label="Permalink to &quot;长期: 统一多平台体验&quot;">​</a></h3><p>最终图景是一个 <strong>一份认知, 多端感知</strong> 的智能体:</p>`,40)),(o(),s(i,null,{default:e(()=>[c(d,{id:"mermaid-382",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20INPUT%5B%22%E8%BE%93%E5%85%A5%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20QQ_IN%5B%22qq%20App%22%5D%0A%20%20%20%20%20%20%20%20TG_IN%5B%22telegram%20App%22%5D%0A%20%20%20%20%20%20%20%20DC_IN%5B%22discord%20App%22%5D%0A%20%20%20%20%20%20%20%20ALARM%5B%22alarm%20App%22%5D%0A%20%20%20%20%20%20%20%20MCP%5B%22mcp%20App%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20CORE%5B%22%E5%B9%B3%E5%8F%B0%E5%B1%82%20%2B%20%E5%86%85%E6%A0%B8%E5%B1%82%20%2B%20%E8%AE%A4%E7%9F%A5%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20PLATFORM%5B%22Platform%22%5D%0A%20%20%20%20%20%20%20%20KERNEL%5B%22Kernel%22%5D%0A%20%20%20%20%20%20%20%20BRAIN%5B%22Brain%20%2F%20%E7%BB%9F%E4%B8%80%E8%AE%B0%E5%BF%86%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20OUTPUT%5B%22%E8%BE%93%E5%87%BA%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20QQ_OUT%5B%22QQ%20%E5%8F%91%E6%B6%88%E6%81%AF%22%5D%0A%20%20%20%20%20%20%20%20TG_OUT%5B%22Telegram%20%E5%8F%91%E6%B6%88%E6%81%AF%22%5D%0A%20%20%20%20%20%20%20%20DC_OUT%5B%22Discord%20%E5%8F%91%E6%B6%88%E6%81%AF%22%5D%0A%20%20%20%20%20%20%20%20TOOL%5B%22%E8%B0%83%E7%94%A8%E5%A4%96%E9%83%A8%E5%B7%A5%E5%85%B7%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20QQ_IN%20--%3E%20PLATFORM%0A%20%20%20%20TG_IN%20--%3E%20PLATFORM%0A%20%20%20%20DC_IN%20--%3E%20PLATFORM%0A%20%20%20%20ALARM%20--%3E%20PLATFORM%0A%20%20%20%20MCP%20--%3E%20PLATFORM%0A%20%20%20%20PLATFORM%20--%3E%20KERNEL%20--%3E%20BRAIN%0A%20%20%20%20BRAIN%20--%3E%20KERNEL%20--%3E%20PLATFORM%0A%20%20%20%20PLATFORM%20--%3E%20QQ_OUT%0A%20%20%20%20PLATFORM%20--%3E%20TG_OUT%0A%20%20%20%20PLATFORM%20--%3E%20DC_OUT%0A%20%20%20%20PLATFORM%20--%3E%20TOOL%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<ul><li>同一个大脑 (认知层) 处理来自不同平台的输入</li><li>统一联合记忆在所有平台间共享, 跨平台上下文无缝衔接</li><li>App 只负责&quot;感知&quot;和&quot;执行&quot;, 不参与决策 -- 决策由内核 + 认知统一做出</li><li>用户可以随时添加新的 App 来接入新平台, 无需修改内核</li></ul><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>跨平台能力</th><th>评价</th></tr></thead><tbody><tr><td>NapCat</td><td>Windows / Linux / macOS / Docker / Termux</td><td>部署环境全覆盖, 无头模式适合服务器</td></tr><tr><td>NoneBot2</td><td>20+ 平台适配器</td><td>框架级跨平台已非常成熟</td></tr><tr><td>OneBot 协议</td><td>多种实现可互换</td><td>不会被单一协议端锁定</td></tr><tr><td>AuroraBot</td><td>当前仅 QQ</td><td>架构已就绪, 只差&quot;写 App&quot;这最后一步</td></tr></tbody></table><blockquote><p>一句话总结: 地基已经打好, 水管也都接好了, 现在只缺给每个房间装上水龙头。</p><p>-- 挼挼</p></blockquote>',5))])}const q=r(h,[["render",A]]);export{P as __pageData,q as default};
